.chatbotToggle {
  width: 80px;
  height: 80px;
  border: 0;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--accent) 0%, #df8d53 100%);
  color: white;
  font-size: 2.2rem;
  cursor: pointer;
  box-shadow: 0 8px 32px rgba(207, 95, 56, 0.5);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
  position: relative;
  animation: chatBounce 2.5s ease-in-out infinite;
}

@keyframes chatBounce {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-6px); }
}

.chatbotToggle:hover {
  animation: none;
  transform: scale(1.12);
  box-shadow: 0 12px 40px rgba(207, 95, 56, 0.6);
}

